90	function regexSplit(text, regex) {
91	    const result = [];
92	    let prev = 0;
93	    for (const match of text.matchAll(regex)) {
94	        const fullMatch = match[0];
95	        if (prev < match.index) {
96	            result.push(text.slice(prev, match.index));
97	        }
98	        if (fullMatch.length > 0) {
99	            result.push(fullMatch);
100	        }
101	        prev = match.index + fullMatch.length;
102	    }
103	    if (prev < text.length) {
104	        result.push(text.slice(prev));
105	    }
106	    return result;
